readable_counts = {k: dict(Counter(v)) for k, v in account_issue_counts.items()}

result = {
    "candidate_accounts": matched_accounts,
    "issue_counts_by_account": readable_counts
}

print("__RESULT__:")
print(json.dumps(result))

